azureLogAnalytics.query:
let recent = ago(5m);
let sizes = AppMetrics | where Name == 'mdk.db.pool.size'    | where TimeGenerated > recent | extend cust = tostring(Properties['customer']), depl = tostring(Properties['deployment']) | where cust in ($customer) or '$customer' == 'All' | summarize Size = avg(ValueSum) by cust, depl;
let idle  = AppMetrics | where Name == 'mdk.db.pool.idle'    | where TimeGenerated > recent | extend cust = tostring(Properties['customer']), depl = tostring(Properties['deployment']) | where cust in ($customer) or '$customer' == 'All' | summarize Idle = avg(ValueSum) by cust, depl;
let inu   = AppMetrics | where Name == 'mdk.db.pool.in_use'  | where TimeGenerated > recent | extend cust = tostring(Properties['customer']), depl = tostring(Properties['deployment']) | where cust in ($customer) or '$customer' == 'All' | summarize InUse = avg(ValueSum) by cust, depl;
let mx    = AppMetrics | where Name == 'mdk.db.pool.max'     | where TimeGenerated > recent | extend cust = tostring(Properties['customer']), depl = tostring(Properties['deployment']) | where cust in ($customer) or '$customer' == 'All' | summarize Max = avg(ValueSum) by cust, depl;
sizes
| join kind=fullouter idle on cust, depl
| join kind=fullouter inu on cust, depl
| join kind=fullouter mx on cust, depl
| project Customer = cust, Deployment = depl, Size, Idle, InUse, Max
| order by Customer asc, Deployment asc
